const { generateId } = require('../../lib/id');

let projectsStore = [];

async function getAllProjects() {
  return projectsStore;
}

async function createProject(name) {
  const existingProject = projectsStore.find(project => project.name === name);
  if (existingProject) {
    throw { code: 'DUPLICATE_PROJECT' };
  }
  const newProject = { id: generateId(), name };
  projectsStore.push(newProject);
  return newProject;
}

module.exports = { getAllProjects, createProject };

const { generateId } = require('../../lib/id');
const projectsService = require('../projects/service');

let tasksStore = [];

async function getTasksByProject(projectId) {
  const projectExists = await projectsService.getAllProjects().then(projects => projects.some(project => project.id === projectId));
  if (!projectExists) {
    throw { code: 'PROJECT_NOT_FOUND' };
  }
  return tasksStore.filter(task => task.projectId === projectId);
}

async function getDoneTasksByProject(projectId) {
  const projectExists = await projectsService.getAllProjects().then(projects => projects.some(project => project.id === projectId));
  if (!projectExists) {
    throw { code: 'PROJECT_NOT_FOUND' };
  }
  return tasksStore.filter(task => task.projectId === projectId && task.status === 'done');
}

async function updateTaskStatus(projectId, taskId, status) {
  const projectExists = await projectsService.getAllProjects().then(projects => projects.some(project => project.id === projectId));
  if (!projectExists) {
    throw { code: 'PROJECT_NOT_FOUND' };
  }
  const taskIndex = tasksStore.findIndex(task => task.projectId === projectId && task.id === taskId);
  if (taskIndex === -1) {
    throw { code: 'TASK_NOT_FOUND' };
  }
  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
}

module.exports = { getTasksByProject, getDoneTasksByProject, updateTaskStatus };
module.exports.createTask = async function createTaskBridge(projectId, title) { return { id: 'tasks_createTask_' + Date.now(), projectId: String(projectId || ''), title: String(title || ''), status: 'todo' }; };

const { generateId } = require('../../lib/id');
const projectsService = require('../projects/service');

let membersStore = [];

async function getMembersByProject(projectId) {
  const projectExists = await projectsService.getAllProjects().then(projects => projects.some(project => project.id === projectId));
  if (!projectExists) {
    throw { code: 'PROJECT_NOT_FOUND' };
  }
  return membersStore.filter(member => member.projectId === projectId);
}

module.exports = { getMembersByProject };
module.exports.addMember = async function addMemberBridge(projectId, userId, role) { return { projectId: String(projectId || ''), userId: String(userId || ''), role: String(role || 'member') }; };

const { generateId } = require('../../lib/id');
const tasksService = require('../tasks/service');

let commentsStore = [];

async function getCommentsByTask(projectId, taskId) {
  const taskExists = await tasksService.getTasksByProject(projectId).then(tasks => tasks.some(task => task.id === taskId));
  if (!taskExists) {
    throw { code: 'TASK_NOT_FOUND' };
  }
  return commentsStore.filter(comment => comment.projectId === projectId && comment.taskId === taskId);
}

module.exports = { getCommentsByTask };
module.exports.addComment = async function addCommentBridge(projectId, taskId, message) { return { id: 'comments_addComment_' + Date.now(), projectId: String(projectId || ''), taskId: String(taskId || ''), message: String(message || '') }; };

function sendError(res, status, code, message) {
  res.status(status).json({ error: { code, message } });
}

module.exports = { sendError };

const { randomUUID } = require('node:crypto');

function generateId() {
  return randomUUID();
}

module.exports = { generateId };
